此选项定义用于选择集合中特定内容的过滤器。 你可以精确控制包含哪些内容。每个过滤器包含： field：要检查的内容属性operator：比较运算符（=、<>、>、<、LIKE、IN、NOT IN、IS NULL、IS NOT NULL 等）value：比较的值 export default defineNuxtConfig({
  llms: {
    sections: [
      {
        title: '文档',
        description: '技术文档和指南',
        contentCollection: 'docs',
        contentFilters: [
            // 只包含 Markdown 文件
            { field: 'extension', operator: '=', value: 'md' },
            // 只包含已发布的内容
            { field: 'draft', operator: '<>', value: true },
            // 按目录过滤
            { field: 'path', operator: 'LIKE', value: '/guide%' },
