默认情况下，您可以在 Markdown 文件内集成任何组件，且它们会在 Studio 中工作且可编辑，但外部组件不会显示在 Studio 的组件列表中，也无法由 Studio 编辑器手动集成。 若要在 Studio 中列出此组件并抓取其所有元数据，您需要在 Nuxt 配置文件中将其设置为全局组件。 以下示例演示如何集成来自 Nuxt UI 库的 Button 和 Icon 组件： export default defineNuxtConfig({
  hooks: {
    'components:extend': (components) => {
      const globals = components.filter(c => ['UButton', 'UIcon'].includes(c.pascalName))

      globals.forEach(c => c.global = true)
    }
  },
})

在专门章节了解更多关于集合模式定义内容。 一旦在集合中定义了 schema 属性，Studio 界面会自动生成对应的表单。 export default defineContentConfig({
  collections: {
    posts: defineCollection({
      type: 'page',
      source: 'blog/*.md',
      schema: z.object({
        draft: z.boolean().default(false),
        category: z.enum(['Alps', 'Himalaya', 'Pyrenees']).optional(),
        date: z.date(),
        image: z.object({
          src: z.string().editor({ input: 'media' }),
          alt: z.string(),
        }),
        slug: z.string().editor({ hidden: true }),
        icon: z.string().optional().editor({ input: 'icon' }),
        authors: z.array(z.object({
          slug: z.string(),
          username: z.string(),
          name: z.string(),
          to: z.string(),
          avatar: z.object({
            src: z.string(),
            alt: z.string(),
          }),
        })),
      }),
    }),
  },
})

这些辅助方法由 Nuxt Content 的 Preview API 提供。 group 方法用于定制父对象。field 方法用于定制输入（即叶子节点）。 import { field, group } from '@nuxt/content/preview'

export default defineNuxtSchema({
  appConfig: {
    parent: group({
      title: '父级标题',
      description: '父级描述。',
      icon: 'i-icon-to-display',
      fields: {
        leaf: field({
          type: '用于编辑该字段的组件类型',
          title: '字段标题',
          description: '字段描述',
          icon: 'i-icon-to-display',
          default: '默认值'
        })
      }
    })
  }
}) 无需必须包含所有的应用配置键；只需添加那些您希望在 Studio 界面展示的字段即可。

field() 方法第一个参数中的 type 可接受多种值： stringnumberbooleanarrayobjecticonmedia 基于这些类型，Studio UI 会适配显示相应的输入类型。例如，icon 类型会显示图标选择器， media 类型会展示媒体库。 如果您在 field() 方法中提供 required 字段，文本输入可以显示为下拉选择而非传统输入框： import { field, group } from '@nuxt/content/preview'

export default defineNuxtSchema({
  appConfig: {
    parent: group({
      title: 'UI',
      description: 'UI 配置',
      icon: 'i-ph-palette-fill',
      fields: {
        primary: field({
          type: 'string',
          title: '主色',
          description: '您的 UI 主色。',
          icon: 'i-ph-palette',
          default: 'sky',
          required: ['sky', 'mint', 'rose', 'amber']
        })
      }
    })
  }
})

一旦您的 schema 部署完成，任何用户都可以访问 Data 区域，使用生成的表单进行操作。 表单中的任何更新都会直接应用到 app.config.ts 文件。您可以在审查页面查看这些更改。 export default defineNuxtSchema({
  ui: group({
    title: 'UI',
    description: 'UI 自定义。',
    icon: 'i-mdi-palette-outline',
    fields: {
      primary: field({
        type: 'string',
        title: '主色',
        description: '您的 UI 主色。',
        icon: 'i-mdi-palette-outline',
        required: ['sky', 'mint', 'rose', 'amber', 'violet', 'emerald', 'fuchsia', '...']
      }),
      gray: field({ ... }),
      icons: group({
        title: '图标',
        description: '管理 UI Pro 中使用的图标。',
        icon: 'i-mdi-application-settings-outline',
        fields: {
          search: field({ ...}),
          dark: field({ ... }),
          light: field({ ... }),
          external: field({ ...}),
          chevron: field({ ... }),
          hash: field({ ... })
        }
      })
    }
  })
